1	import { OutlineBlock, MarkdownParseResult } from './types';
2	import { generateId } from './utils';
3	
4	export class OutlineParser {
5	    
6	    /**
7	     * 将 Markdown 文本解析为大纲块结构
8	     * 支持所有 Markdown 元素类型
9	     * 
10	     * 策略：
11	     * 1. 列表项：逐行解析，构建层级结构（WorkFlowy 风格）
12	     * 2. 其他内容：合并连续的非列表行为一个块，交给 Obsidian 渲染器处理
13	     */
14	    parseMarkdown(content: string): MarkdownParseResult {
15	        const lines = content.split('\n');
16	        const flatBlocks: OutlineBlock[] = [];
17	        let totalBlocks = 0;
18	        let maxLevel = 0;
19	
20	        // 用于累积连续的非列表内容
21	        let nonListLines: string[] = [];
22	
23	        const flushNonListBlock = () => {
24	            if (nonListLines.length > 0) {
25	                const blockContent = nonListLines.join('\n').trim();
26	                if (blockContent) {
27	                    flatBlocks.push({
28	                        id: generateId(),
29	                        type: 'paragraph',  // 统一作为段落，让 Obsidian 渲染器处理
30	                        content: blockContent,
31	                        level: 0,
32	                        collapsed: false,
33	                        children: [],
34	                        editable: true,
35	                        useObsidianRenderer: true
36	                    });
37	                    totalBlocks++;
38	                }
39	                nonListLines = [];
40	            }
41	        };
42	
43	        for (let i = 0; i < lines.length; i++) {
44	            const line = lines[i];
45	            const trimmed = line.trim();
46	
47	            // 检测列表项
48	            const listMatch = line.match(/^(\s*)([-*+]|\d+\.)\s+(.*)$/);
49	            if (listMatch) {
50	                // 先刷新之前累积的非列表内容
51	                flushNonListBlock();
52	
53	                const [, indent, , text] = listMatch;
54	                // 计算缩进层级：优先检测Tab，其次检测空格（兼容性）
55	                const tabCount = (indent.match(/\t/g) || []).length;
56	                const spaceCount = (indent.match(/ /g) || []).length;
57	                const level = tabCount > 0 ? tabCount : Math.floor(spaceCount / 2); // Tab优先，否则每2个空格为一级
58	                maxLevel = Math.max(maxLevel, level);
59	
60	                // 检测待办事项
61	                let isTodo = false;
62	                let todoCompleted = false;
63	                let content = text;
64	                
65	                const todoMatch = text.match(/^\[([ xX])\]\s+(.*)$/);
66	                if (todoMatch) {
67	                    isTodo = true;
68	                    todoCompleted = todoMatch[1].toLowerCase() === 'x';
69	                    content = todoMatch[2];
70	                }
71	
72	                // 检查后续行是否是续行（缩进但没有列表标记）
73	                let j = i + 1;
74	                while (j < lines.length) {
75	                    const nextLine = lines[j];
76	                    const nextTrimmed = nextLine.trim();
77	                    
78	                    // 空行跳过
79	                    if (!nextTrimmed) {
80	                        j++;
81	                        continue;
82	                    }
83	                    
84	                    // 检查是否是续行（有缩进但没有列表标记）
85	                    const continuationMatch = nextLine.match(/^(\s+)([^-*+\d].*)$/);
86	                    if (continuationMatch) {
87	                        const [, nextIndent, continuationText] = continuationMatch;
88	                        // 续行的缩进应该比列表项多（至少2个空格或1个tab）
89	                        const nextIndentLength = nextIndent.length;
90	                        const currentIndentLength = indent.length;
91	                        
92	                        if (nextIndentLength > currentIndentLength) {
93	                            // 这是续行，添加到内容中
94	                            content += '\n' + continuationText.trim();
95	                            j++;
96	                        } else {
97	                            break;
98	                        }
99	                    } else {
100	                        // 不是续行，退出
101	                        break;
102	                    }
103	                }
104	                
105	                // 更新索引，跳过已处理的续行
106	                i = j - 1;
107	
108	                flatBlocks.push({
109	                    id: generateId(),
110	                    type: 'list',
111	                    content,
112	                    level,
113	                    collapsed: false,
114	                    children: [],
115	                    isTodo,
116	                    todoCompleted,
117	                    editable: true,
118	                    useObsidianRenderer: false  // 列表项使用 WorkFlowy 风格渲染
119	                });
120	                totalBlocks++;
121	                continue;
122	            }
123	
124	            // 非列表内容：累积到 nonListLines
125	            nonListLines.push(line);
126	        }
127	
128	        // 处理最后剩余的非列表内容
129	        flushNonListBlock();
130	
131	        // 构建层级关系（只对列表项）
132	        const blocks = this.buildHierarchy(flatBlocks);
133	
134	        return {
135	            blocks,
136	            metadata: {
137	                totalBlocks,
138	                maxLevel
139	            }
140	        };
141	    }
142	
143	    /**
144	     * 构建列表项的层级关系
145	     * 非列表项作为顶级块，列表项按缩进构建树形结构
146	     */
147	    private buildHierarchy(flatBlocks: OutlineBlock[]): OutlineBlock[] {
148	        const result: OutlineBlock[] = [];
149	        const stack: OutlineBlock[] = [];
150	
151	        for (const block of flatBlocks) {
152	            // 非列表项直接作为顶级块
153	            if (block.type !== 'list') {
154	                result.push(block);
155	                stack.length = 0; // 清空栈
156	                continue;
157	            }
158	
159	            // 列表项：构建层级关系
160	            while (stack.length > 0 && stack[stack.length - 1].level >= block.level) {
161	                stack.pop();
162	            }
163	
164	            if (stack.length === 0) {
165	                result.push(block);
166	            } else {
167	                const parent = stack[stack.length - 1];
168	                parent.children.push(block);
169	                block.parent = parent;
170	            }
171	
172	            stack.push(block);
173	        }
174	
175	        return result;
176	    }
177	    
178	    /**
179	     * 将大纲块结构转换为 Markdown 文本
180	     * 支持所有块类型
181	     */
182	    blocksToMarkdown(blocks: OutlineBlock[]): string {
183	        const lines: string[] = [];
184	
185	        function processBlock(block: OutlineBlock, parentLevel: number = 0) {
186	            switch (block.type) {
187	                case 'heading':
188	                    const hashes = '#'.repeat(block.headingLevel || 1);
189	                    lines.push(`${hashes} ${block.content}`);
190	                    break;
191	
192	                case 'code':
193	                    lines.push('```' + (block.codeLanguage || ''));
194	                    lines.push(block.content);
195	                    lines.push('```');
196	                    break;
197	
198	                case 'quote':
199	                    const quotes = '>'.repeat(block.quoteLevel || 1);
200	                    lines.push(`${quotes} ${block.content}`);
